PR = PolynomialRing(ZZ, 'x')
x = PR.gen()
f = x**4 - a_3 * x**3 + a_2 * x**2 - a_1 * x + a_0
roots = f.roots()
phi = 1
for root in roots:
    assert is_prime(root[0])
    phi *= (root[0] - 1)

d = pow(65537, -1, phi)
m = int(pow(ct, int(d), N))
print(m.to_bytes(m.bit_length() // 8 + 1, 'big'))

